// Decode RLE frame into buffer (400 bytes)
inline void sprite_decode_frame(uint16_t frameIdx, uint8_t* buf) {
  uint16_t off = pgm_read_word(&sprite_rle_offset[frameIdx]);
  int pos = 0;
  while (pos < SPRITE_W * SPRITE_H) {
    uint8_t count = pgm_read_byte(&sprite_rle_data[off++]);
    uint8_t val = pgm_read_byte(&sprite_rle_data[off++]);
    for (uint8_t i = 0; i < count && pos < SPRITE_W * SPRITE_H; i++)
      buf[pos++] = val;
  }
}
